import React from 'react';
import './Settings.css';

import HeaderMenteeDashboard from "../../../Components/Layouts/DashboardLayout/MenteeLayout/HeaderMenteeDashboard";
import MenteeSidebar from "../../../Components/Layouts/DashboardLayout/MenteeLayout/MenteeSidebar";
import { Tab, Tabs } from "react-bootstrap";
import ProfileTab from './Component/ProfileTab';
import AccountSettingTab from './Component/AccountSettingTab';
import BillingTab from './Component/BillingTab';
import PaymentTab from './Component/PaymentTab';
import ApiRequest from '../../../Services/ApiRequest';
import Loading from '../../../Utils/Loading';

class Settings extends React.Component {
    state = {
        personalInfo: [],
        countries: [],
        cities: [],
        country:{},
        city:{},
        loading:true
    }
    componentDidMount() {
        this.getPersonalInfo();
        this.getCountries();
    }

    getPersonalInfo = async () => {
        const profile = await ApiRequest.getRequest('/getUserInfo');
        console.log(profile);
        if (profile && profile.status === 200) {
            this.setState({
                personalInfo: profile.data.userInfo,
                loading:false,
                city:{
                    value:profile.data.userInfo?.[0]?.personal_info?.city?.id,
                    label:profile.data.userInfo?.[0]?.personal_info?.city?.name
                },
                country:{
                    value:profile.data.userInfo?.[0]?.personal_info?.country?.id,
                    label:profile.data.userInfo?.[0]?.personal_info?.country?.name
                },
            })
            if (profile.data.user?.country?.id) {
                this.getCityByCountryID(profile.data.user?.country?.id)
            }
        }
    }
    getCountries = async () => {
        const getCountries = await ApiRequest.getRequest('/getCountries');
        if (getCountries && getCountries.data.countries && getCountries.status === 200) {
            this.setState({
                countries: getCountries.data.countries
            })
        }
    }
    getCityByCountryID = async (id) => {
        if (id !== undefined) {
            const response = await ApiRequest.getRequest(`/getCountryCities/${id}`);
            if (response && response.status === 200) {
                this.setState({
                    cities: response.data.cities,

                })
            }
        }
    }
    // On change Country and city in child component
    onChangeCountry = (event) => {
        console.log(event)
        const { value, label } = event
        this.setState({
            country_id: value,
            country: {
                value: value,
                label: label
            }
        })
        this.getCityByCountryID(value);
    }
    onChangeCity = (event) => {
        const { value, label } = event
        this.setState({
            city_id: value,
            city: {
                value: value,
                label: label
            }
        })
    }
    render() {
        return (
            <div className="container-fluid dashboard-body-bg p-0">
                <div className='dashboard'>
                    <MenteeSidebar />
                    <div className='dashboard-app'>
                        <HeaderMenteeDashboard />
                        <div className='container-fluid ProfileWrap'>
                            <div className="row mar-width-0 settingsWrap">
                                <Tabs defaultActiveKey="home" id="uncontrolled-tab-example" className="mb-3">
                                    <Tab eventKey="home" title="Profile">
                                        <ProfileTab personalInfo={this.state.personalInfo} countries={this.state.countries} cities={this.state.cities} onChangeCountry={this.onChangeCountry} onChangeCity={this.onChangeCity} city={this.state.city} country={this.state.country} />
                                    </Tab>
                                    <Tab eventKey="profile" title="Account Settings">
                                        <AccountSettingTab />
                                    </Tab>
                                    <Tab eventKey="home2" title="Billing">
                                        <BillingTab />
                                    </Tab>
                                    <Tab eventKey="profile2" title="Payment History">
                                        <PaymentTab />
                                    </Tab>
                                </Tabs>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        )
    }
}

export default Settings;
