import React from 'react';
import { Link } from "react-router-dom";
import Message from "../../../../assets/images/DashboardImgs/message-circle.png";
import Users from "../../../../assets/images/DashboardImgs/users.png";
import Rectangle from "../../../../assets/images/DashboardImgs/Rectangle.png";
import { destroySession } from '../../../../Helpers/Functions';
import ApiRequest from '../../../../Services/ApiRequest';
import store from '../../../../app/store';
import { connect } from "react-redux";




class HeaderMenteeDashboard extends React.Component {
    state = {
        personalInfo: [],
        image: '',
    }
    logout() {
        localStorage.clear();
        destroySession();
    }
    componentDidMount() {
        this.getPersonalInfo()
        if (store.getState().profileImage) {
            this.setState({
                image: store.getState().profileImage
            })
        }
    }
    getPersonalInfo = async () => {
        const profile = await ApiRequest.getRequest('/getUserInfo');
        console.log(profile);
        if (profile && profile.status === 200 && profile.data.userInfo?.[0]?.personal_info?.profile_image) {
            this.setState({
                personalInfo: profile.data.userInfo,
                image: process.env.REACT_APP_BASEURL + profile.data.userInfo?.[0]?.personal_info?.profile_image
            });
        }
    }
    render() {
        return (
            <header className='dashboard-toolbar'>
                <div className="row mar-width-0">
                    <div className="col-md-6">
                    </div>
                    <div className="col-md-6 text-right">
                        <ul className="ms-auto mb-0">
                            <li className="nav-item dropdown user-dropdown d-inline-block">
                                <Link to="/" className="nav-link nav-bell-icon">
                                    <img src={Users} className="w-22px" alt="" />
                                </Link>
                            </li>
                            <li className="nav-item dropdown user-dropdown d-inline-block">
                                <Link to="/" className="nav-link nav-bell-icon">
                                    <img src={Message} className="w-22px" alt="" />
                                    <span className="badge badge-pill badge-primary">4</span>
                                </Link>
                            </li>
                            <li className="nav-item dropdown user-dropdown d-inline-block">
                                <Link to="/" className="nav-link nav-bell-icon">
                                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20"
                                        viewBox="0 0 24 24" fill="none" stroke="currentColor"
                                        stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
                                        className="feather feather-bell align-middle">
                                        <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path>
                                        <path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
                                    </svg>
                                    <span className="badge badge-pill badge-primary">2</span>
                                </Link>
                            </li>

                            <li className="nav-item dropdown user-dropdown d-inline-block">
                                <Link to="/" className="nav-link dropdown-toggle"
                                    id="navbarDropdownMenuLink" role="button" data-bs-toggle="dropdown"
                                    aria-expanded="false">
                                    
                                    <img src={store.getState().profileImage? store.getState().profileImage : (this.state.image ? this.state.image : Rectangle)} className="sidebar-icon-" alt="" />  <span>Abdelwadood</span>
                                </Link>
                                <ul className="dropdown-menu shadow-sm"
                                    aria-labelledby="navbarDropdownMenuLink">
                                    <li><Link to="/Profile" className="dropdown-item" >Profile</Link></li>
                                    <li><Link to="#" className="dropdown-item" >Another action</Link></li>
                                    <li><Link to="#" className="dropdown-item" >Something else here</Link>
                                    </li>
                                    <li ><Link to="/" className="dropdown-item" onClick={() => this.logout()}>Logout</Link></li>
                                </ul>
                            </li>
                        </ul>
                    </div>
                </div>
            </header>
        );
    }
}
const mapStateToProps = state => {
    return {
        profileImage: state.profileImage,
    };
};

export default connect(mapStateToProps)(HeaderMenteeDashboard);
