import React from "react";
import Avatar from "../../../../assets/images/DashboardImgs/avatar.png";
import Select from 'react-select'
import TimezoneSelect from "react-timezone-select"
import { months } from "moment";
import { countBy } from "lodash";
import ApiRequest from "../../../../Services/ApiRequest";
import store from "../../../../app/store";
import { addProfileImage } from "../../../../app/Actions";
import { toasterAlert } from "../../../../Helpers/Functions";

class ProfileTab extends React.Component {
    state = {
        profileInfo: [],
        month: 1,
        day: '',
        year: '',
        countries: [],
        cities: [],
        city_id: '',
        city: {},
        country_id: '',
        country: {},
        timeZone: '',
        profile_image: '',
        display_name: '',
        image: '',
        gender: 1,
        first_name: '',
        last_name: '',
        error: {},
        date_of_birth: ''
    }
    componentDidMount() {
        console.log(store.getState());
        this.years();
    }
    static getDerivedStateFromProps(props, state) {
        return {
            profileInfo: props.personalInfo?.[0],
            countries: props?.countries,
            cities: props?.cities,
            city: props?.city,
            country: props?.country,
        };
    }
    fillTheState = () => {
        if (this.state.profileInfo && !this.state.display_name && !this.state.image && this.state.profileInfo?.personal_info?.display_name && this.state.profileInfo?.personal_info?.date_of_birth) {
            this.setState({
                gender: this.state.profileInfo?.personal_info?.gender,
                display_name: this.state.profileInfo?.personal_info?.display_name,
                profile_image: process.env.REACT_APP_BASEURL + this.state.profileInfo?.personal_info?.profile_image,
                date_of_birth: this.state.profileInfo?.personal_info?.date_of_birth,
            }, () => {
                let d = this.state?.date_of_birth;
                if (d) {
                    let arr = d.split('-');
                    let month = arr[1].replace('0', '')
                    this.setState({
                        day: arr[2],
                        month: month,
                        year: arr[0]
                    })
                }
            })
        }
        if (this.state.profileInfo?.zone && !this.state.timeZone) {
            this.setState({
                timeZone: {
                    abbrev: this.state.profileInfo?.zone?.abbrev,
                    altName: this.state.profileInfo?.zone?.altName,
                    label: this.state.profileInfo?.zone?.label,
                    offset: this.state.profileInfo?.zone?.offset,
                    value: this.state.profileInfo?.zone?.value
                }
            })
        }
    }
    selectToCountries = () => {
        if (this.state?.countries) {
            if (this.state?.profileInfo?.country?.id) {
                this.setState({
                    country: {
                        value: this.state?.profileInfo?.country?.id,
                        label: this.state?.profileInfo?.country?.name,
                    },
                    city: {
                        value: this.state?.profileInfo?.city?.id,
                        label: this.state?.profileInfo?.city?.name,
                    },
                })
            }
            let option = [];
            this.state.countries.map(el => {
                let arr = {
                    value: el.id,
                    label: el.name
                };
                option.push(arr);
            })
            return (
                <Select options={option} onChange={(e) => this.props.onChangeCountry(e)} value={this.state.country} />
            );
        }
    }
    selectToCities = () => {
        if (this.state?.cities) {
            if (this.state.profileInfo?.first_name && !this.state.first_name) {
                this.setState({
                    first_name: this.state.profileInfo?.first_name,
                    last_name: this.state.profileInfo?.last_name,
                })
            }
            let option = [];
            this.state.cities.map(el => {
                let arr = {
                    value: el.id,
                    label: el.name
                };
                option.push(arr);
            })
            return (
                <Select options={option} onChange={(e) => this.props.onChangeCity(e)} value={this.state.city} />
            );
        }
    }
    // Days Options
    days = () => {
        const monthDays = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
        let i = this.state.month - 1;
        let option = [];
        let day = 1;
        for (let index = 0; index < monthDays[i]; index++) {
            option.push(<option value={day}>{day}</option>)
            day++;
        }
        return option;

    }
    //100 Year Options
    years = () => {
        const currentDate = new Date();
        let currentYear = currentDate.getFullYear();
        let arr = [];
        for (let index = 0; index < 100; index++) {
            arr.push(<option value={currentYear}>{currentYear}</option>)
            currentYear = --currentYear;
        }
        return arr;
    }

    handleChange = (event) => {
        const { name, value } = event.target;
        this.setState({
            [name]: value
        })
    }
    handleFileChange = (event) => {
        if (event.target.files[0]) {
            this.getBase64(event.target.files[0], (result) => {

                this.setState({
                    image: result,
                    profile_image: result,
                })
            });
        }
    }
    selectedTimeZone = (val) => {
        this.setState({
            timeZone: val
        })
    }
    getBase64(file, cb) {
        let reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = function () {
            cb(reader.result)
        };
        reader.onerror = function (error) {
            console.log('Error: ', error);
        };
    }
    handleSubmit = async (event) => {
        event.preventDefault();
        console.log(store.getState());
        const { first_name, last_name, display_name, day, month, year, city, country, timeZone, gender, profile_image } = this.state;
        let { firstNameError, lastNameError, displayNameError, dayError, monthError, yearError, cityError, countryError, timeZoneError, genderError } = '';
        if (!first_name) {
            firstNameError = "This field is required."
        }
        if (!last_name) {
            lastNameError = "This field is required."
        }
        if (!display_name) {
            displayNameError = "This field is required."
        }
        if (!day) {
            dayError = "This field is required."
        }
        if (!month) {
            monthError = "This field is required."
        }
        if (!year) {
            yearError = "This field is required."
        }
        if (!city) {
            cityError = "This field is required."
        }
        if (!country) {
            countryError = "This field is required."
        }
        if (!timeZone) {
            timeZoneError = "This field is required."
        }
        if (!gender) {
            genderError = "This field is required."
        }
        this.setState({
            error: {
                firstNameError: firstNameError,
                lastNameError: lastNameError,
                displayNameError: displayNameError,
                dayError: dayError,
                monthError: monthError,
                yearError: yearError,
                timeZoneError: timeZoneError,
                genderError: genderError,
            }
        })
        if (firstNameError || lastNameError || displayNameError || dayError || monthError || yearError || timeZoneError || genderError) {
            return
        }
        let date_of_birth = year + '-' + month + '-' + day;
        const image = this.state.image
        const response = await ApiRequest.postRequest('/profileSetting', {
            first_name,
            last_name,
            date_of_birth,
            country: country.value,
            city: city.value,
            timeZone,
            gender,
            image: image,
            display_name
        })
        if (response && response.status === 200) {
            toasterAlert('success', "User data successfully updated");
            if (response.data?.profile?.profile_image) {
                store.dispatch(addProfileImage(process.env.REACT_APP_BASEURL + response.data?.profile?.profile_image));
                console.log(store.getState());
            }
        }

    }
    render() {
        this.fillTheState();
        const { timeZone } = this.state;
        return (
            <div className="row mar-width-0 bg-body">

                <div className="col-md-8">
                    <div className="row mar-width-0">
                        <form action="" className="form-wrap" onSubmit={this.handleSubmit}>
                            <div className="row mar-width-0 ">
                                <div className="col-md-2 p-0 mb-54">
                                    <div className="image-upload">
                                        <label htmlFor="file-input">
                                            <img src={this.state.profile_image ? this.state.profile_image : Avatar} className="w-100" />
                                        </label>

                                        <input id="file-input" type="file" onChange={this.handleFileChange} />
                                    </div>
                                </div>
                                <div className="col-md-9 avatar-heading mb-54">
                                    <h6>Change avatar</h6>
                                    <p>Images must be .jpg or .png with minimum size of 160x160 pixels.</p>
                                </div>
                                <div className="col-md-12 p-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Display Name</label>
                                        <input type="text" name="display_name" value={this.state.display_name} className="form-control" placeholder="Enter your display name" onChange={this.handleChange} />
                                    </div>
                                </div>
                                <div className="col-md-6 pl-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Your Name</label>
                                        <input type="text" name="first_name" className="form-control" placeholder="Enter your first name" value={this.state.first_name} onChange={this.handleChange} />
                                    </div>
                                </div>
                                <div className="col-md-6 pr-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput"></label>
                                        <input type="text" name="last_name" className="form-control" placeholder="Enter your last name" value={this.state.last_name} onChange={this.handleChange} />
                                    </div>
                                </div>
                                <div className="col-md-3 pl-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Birthday</label>
                                        <select className="form-select form-control form-select-lg mb-3"
                                            aria-label=".form-select-lg example" name="day" value={this.state.day} onChange={this.handleChange}>
                                            <option selected>Day</option>
                                            {this.days()}
                                        </select>
                                    </div>
                                </div>
                                <div className="col-md-3 pr-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput"></label>
                                        <select className="form-select form-control form-select-lg mb-3"
                                            aria-label=".form-select-lg example" name="month" onChange={this.handleChange} value={this.state.month}>
                                            <option selected>Month</option>
                                            <option value="1">January</option>
                                            <option value="2">February</option>
                                            <option value="3">March</option>
                                            <option value="4">April</option>
                                            <option value="5">May</option>
                                            <option value="6">June</option>
                                            <option value="7">Jully</option>
                                            <option value="8">August</option>
                                            <option value="9">September</option>
                                            <option value="10">October</option>
                                            <option value="11">November</option>
                                            <option value="12">December</option>
                                        </select>
                                    </div>
                                </div>
                                <div className="col-md-3 pr-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput"></label>
                                        <select className="form-select form-control form-select-lg mb-3"
                                            aria-label=".form-select-lg example" value={this.state.year} name="year" onChange={this.handleChange}>
                                            <option selected>Year</option>
                                            {this.years()}
                                        </select>
                                    </div>
                                </div>
                                <div className="col-md-6 pl-0 d-none">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">From</label>
                                        <select className="form-select form-control form-select-lg mb-3"
                                            aria-label=".form-select-lg example">
                                            <option selected>Australia</option>
                                            <option value="1">One</option>
                                            <option value="2">Two</option>
                                            <option value="3">Three</option>
                                        </select>
                                    </div>
                                </div>
                                <div className="col-md-6 pr-0 d-none">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput"></label>
                                        <select className="form-select form-control form-select-lg mb-3"
                                            aria-label=".form-select-lg example">
                                            <option selected>Rathdowney</option>
                                            <option value="1">One</option>
                                            <option value="2">Two</option>
                                            <option value="3">Three</option>
                                        </select>
                                    </div>
                                </div>
                                <div className="col-md-6 pl-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Living in</label>
                                        {this.selectToCountries()}
                                    </div>
                                </div>
                                <div className="col-md-6 pr-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput"></label>
                                        {this.selectToCities()}
                                    </div>
                                </div>
                                <div className="col-md-12 p-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Timezone</label>
                                        <TimezoneSelect
                                            value={timeZone}
                                            onChange={this.selectedTimeZone}
                                        />
                                    </div>
                                </div>
                                <div className="col-md-12 p-0">
                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Gender</label>
                                        <select className="form-select form-control form-select-lg mb-3"
                                            aria-label=".form-select-lg example" name="gender" onChange={this.handleChange} value={this.state.gender}>
                                            <option value="1" selected>Male</option>
                                            <option value="2">Female</option>
                                            <option value="3">Other</option>
                                        </select>

                                    </div>
                                </div>
                            </div>
                            <div className="col-md-12 text-right">
                                <button type="submit" className="btn btn-primary btnLogin w-25">Save Changes</button>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        );
    }
}

export default ProfileTab;